VALUES
  ('heelevel3-6e2f88c7-moex-00232', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲未婚產下乙，產後缺少照護而病故。乙成人後查明充分證據，乙係甲自丙受胎所生。乙找到丙 要求其應負責，丙因配偶丁在場而噤聲不語。下列敘述，何者正確？', '["因乙對丙之要求，已發生請求認領之效力，故乙為丙之準婚生子女", "如丙於遺囑中表示認領乙，因乙不知，故不生認領效力", "乙於丙死後，得向丙之繼承人丁提起認領之訴", "乙於丙死後向丁提起認領之訴，乙自勝訴判決確定日起，方為丙之繼承人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00233', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '遺囑未指定遺囑執行人，並未委託他人指定者，得由何人選定之？', '["遺囑管理人", "親屬會議", "繼承人", "檢察官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00234', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列何種行為，雖經法定代理人允許，限制行為能力人亦不得為之？', '["加入漁會成為會員", "在票據上簽名", "擔任合會之會首", "加入職業工會成為會員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00235', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列有關人事保證人責任之敘述，何者錯誤？', '["以受僱人將來因職務上行為應對僱用人負賠償責任者為限", "以僱用人不能依他項方法受賠償者為限", "以賠償事故發生時，受僱人2年內可得報酬之總額為限", "未定期間者，以自保證成立之日起3年內發生之賠償事故為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00236', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '債務人怠於向第三人索還欠款時，債權人因保全債權，得以自己之名義，行使代位權之範圍，下 列何者不包括之？', '["假扣押", "實行擔保物權", "提起異議之訴", "扶養請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00237', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '乙向甲租用專業攝影機，甲應允並將其所有之攝影機交付於乙使用。其後乙得甲之同意，復將該 攝影機轉租並交付於丙使用；丙外出攝影，均由緊隨其旁之助理丁協助將該攝影機架設於腳架上。 當丁執此攝影機架設於腳架上時，何者非該攝影機之占有人？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00238', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於生前特種贈與之敘述，何者錯誤？', '["因留學所贈與之學費", "因出嫁所贈與之嫁妝", "因營業所贈與之資本", "因分居所贈與之費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00239', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-111-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '設甲於民國103年7月間死亡，甲有繼承人為乙、丙。甲留有數筆債務與存款、動產；甲立有遺 囑為遺贈。下列敘述，何者錯誤？', '["乙、丙在法院依公示催告程序公告，命甲之債權人於一定期限內報明其債權之期限內，不得對 於甲之任何債權人償還債務", "乙、丙中之一人如陳報遺產清冊，其他繼承人視為已陳報", "乙、丙開具遺產清冊陳報法院時，法院應同時指定會同開具財產清冊之人", "乙、丙非依規定償還債務後，不得向受遺贈人交付遺贈"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
